  1→import './editor.css';
  2→import { motion, AnimatePresence } from "framer-motion";
  3→import React, { useCallback, useEffect, useState, useRef } from 'react';
  4→import { useLexicalComposerContext } from "@lexical/react/LexicalComposerContext";
  5→import EditorInner from './RichTextEditor.jsx';
  6→import { $getRoot } from 'lexical';
  7→import { deleteJournalImage, saveDraft } from '../../../../API/Api.js';
  8→import { useAuth } from '../../../Context/useAuth.js';
  9→import { useQueryClient } from '@tanstack/react-query';
 10→
 11→class ErrorBoundary extends React.Component {
 12→  state = { error: null };
 13→  static getDerivedStateFromError(error) {
 14→    return { error };
 15→  }
 16→  render() {
 17→    if (this.state.error) {
 18→      return <div>Error: {this.state.error.message}</div>;
 19→    }
 20→    return this.props.children;
 21→  }
 22→}
 23→
 24→const Editor=({onClose, initialTitle = '', promptId = null, promptText = null, draftId = null, draftContent = null}) =>{
 25→    const {session} = useAuth();
 26→    const queryClient = useQueryClient();
 27→
 28→    const [title, setTitle] = useState(initialTitle || '')
 29→    const [wordCount, setWordCount] = useState(0);
 30→    const [editor] = useLexicalComposerContext();
 31→    const currentDraftIdRef = useRef(draftId);
 32→    const editorStateRef = useRef({ hasChanges: false, hasContent: false, editorState: null, title: '' });
 33→    const [showCloseConfirm, setShowCloseConfirm] = useState(false);
 34→    const [isSavingDraft, setIsSavingDraft] = useState(false);
 35→    const [saveError, setSaveError] = useState(false);
 36→    const saveButtonRef = useRef(null);
 37→    const isClosingRef = useRef(false);
 38→
 39→    const [uploadedImagePaths, setUploadedImagePaths] = useState([]);
 40→
 41→    const addUploadedImagePath = useCallback((imagePath) =>{
 42→      setUploadedImagePaths((prev) => [...prev, imagePath]);
 43→    }, [])
 44→
 45→    useEffect(() => {
 46→        setTitle(initialTitle || '');
 47→    }, [initialTitle]);
 48→
 49→    // Load draft content into Lexical editor on mount
 50→    useEffect(() => {
 51→        if (draftContent && editor) {
 52→            try {
 53→                const parsedState = editor.parseEditorState(draftContent);
 54→                editor.setEditorState(parsedState);
 55→            } catch (err) {
 56→                console.error('Failed to load draft content:', err);
 57→            }
 58→        }
 59→    }, [draftContent, editor]);
 60→
 61→    const handleDraftIdCreated = useCallback((newDraftId) => {
 62→        currentDraftIdRef.current = newDraftId;
 63→    }, []);
 64→
 65→    const handleCloseEditor = useCallback(async() => {
 66→      // Only delete uploaded images if there's no saved draft
 67→      // (drafts own their images)
 68→      if(uploadedImagePaths.length > 0 && !currentDraftIdRef.current){
 69→        const message = await deleteJournalImage(session?.access_token, uploadedImagePaths)
 70→        if(message){
 71→          // console.log(message.message)
 72→        }
 73→      }
 74→
 75→        editor.update(() => {
 76→            const root = $getRoot();
 77→            root.clear();
 78→            onClose();
 79→        })
 80→    }, [editor, onClose, session?.access_token, uploadedImagePaths])
 81→
 82→    const handleCloseEditorOnSave = useCallback(async() => {
 83→      editor.update(() => {
 84→            const root = $getRoot();
 85→            root.clear();
 86→            onClose();
 87→      })
 88→    }, [onClose, editor])
 89→
 90→    const handleCloseClick = useCallback(() => {
 91→        if (isClosingRef.current) return;
 92→        const { hasChanges, hasContent } = editorStateRef.current;
 93→        if (hasChanges && hasContent) {
 94→            setShowCloseConfirm(true);
 95→        } else {
 96→            isClosingRef.current = true;
 97→            handleCloseEditor();
 98→        }
 99→    }, [handleCloseEditor])
100→
101→    const handleConfirmSaveDraft = useCallback(async () => {
102→        let currentEditorState;
103→        editor.read(() => {
104→            currentEditorState = JSON.stringify(editor.getEditorState().toJSON());
105→        });
106→        if (!currentEditorState || !session?.access_token) {
107→            handleCloseEditor();
108→            return;
109→        }
110→        setSaveError(false);
111→        setIsSavingDraft(true);
112→
113→        // Cancel pending auto-save timer
114→        if (editorStateRef.current.saveTimerRef) {
115→            clearTimeout(editorStateRef.current.saveTimerRef.current);
116→        }
117→
118→        try {
119→            await saveDraft(session.access_token, {
120→                content: currentEditorState,
121→                title: title || '',
122→                draftId: currentDraftIdRef.current || null,
123→                prompt_id: promptId || null,
124→            });
125→            queryClient.invalidateQueries({ queryKey: ['journal-drafts'], refetchType: 'active' });
126→            handleCloseEditorOnSave();
127→        } catch (err) {
128→            console.error('Failed to save draft on close:', err);
129→            setSaveError(true);
130→            setIsSavingDraft(false);
131→        }
132→    }, [editor, session?.access_token, title, promptId, queryClient, handleCloseEditor, handleCloseEditorOnSave])
133→
134→    const handleConfirmDiscard = useCallback(() => {
135→        setShowCloseConfirm(false);
136→        handleCloseEditor();
137→    }, [handleCloseEditor])
138→
139→    // Escape key dismisses dialog
140→    useEffect(() => {
141→        if (!showCloseConfirm) return;
142→        const handleKeyDown = (e) => {
143→            if (e.key === 'Escape') handleConfirmDiscard();
144→        };
145→        document.addEventListener('keydown', handleKeyDown);
146→        return () => document.removeEventListener('keydown', handleKeyDown);
147→    }, [showCloseConfirm, handleConfirmDiscard]);
148→
149→    // Auto-focus Save Draft button when dialog opens
150→    useEffect(() => {
151→        if (showCloseConfirm) saveButtonRef.current?.focus();
152→    }, [showCloseConfirm]);
153→
154→    return(
155→        <>
156→        <div className='editor-parent-container'>
157→
158→            <motion.div
159→            initial={{scale: 0, opacity: 0.8}}
160→            animate={{scale: 1, opacity: 1}}
161→            exit={{scale: 0.8, opacity: 0,}}
162→            transition={{type: 'spring', stiffness: 260, damping: 25}}
163→            className="editor-container"
164→            >
165→                <div className='editor-close-bttn-container'>
166→                    <button
167→                        onClick={handleCloseClick}
168→                        className='editor-close-bttn'
169→                        aria-label="Close editor"
170→                        title="Close"
171→                    >
172→                        <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="m256-200-56-56 224-224-224-224 56-56 224 224 224-224 56 56-224 224 224 224-56 56-224-224-224 224Z"/></svg>
173→                    </button>
174→                </div>
175→
176→                <input value={title} onChange={(e) => setTitle(e.target.value)} className='content-title-input' type="text" placeholder='Title' />
177→
178→                <div className="editor-mode-shell">
179→                    <ErrorBoundary>
180→                        <EditorInner
181→                            addUploadImagesPath={addUploadedImagePath}
182→                            onclose={handleCloseEditor}
183→                            onCloseOnSave={handleCloseEditorOnSave}
184→                            title={title}
185→                            setWordCount={setWordCount}
186→                            wordCount={wordCount}
187→                            promptId={promptId}
188→                            draftId={draftId}
189→                            onDraftIdCreated={handleDraftIdCreated}
190→                            editorStateRef={editorStateRef}
191→                        />
192→                    </ErrorBoundary>
193→                </div>
194→                <AnimatePresence>
195→                    {showCloseConfirm && (
196→                        <motion.div
197→                            className="editor-close-confirm-overlay"
198→                            initial={{ opacity: 0 }}
199→                            animate={{ opacity: 1 }}
200→                            exit={{ opacity: 0 }}
201→                            transition={{ duration: 0.15 }}
202→                            onClick={handleConfirmDiscard}
203→                        >
204→                            <motion.div
205→                                className="editor-close-confirm-card"
206→                                initial={{ scale: 0.9, opacity: 0 }}
207→                                animate={{ scale: 1, opacity: 1 }}
208→                                exit={{ scale: 0.9, opacity: 0 }}
209→                                transition={{ type: 'spring', stiffness: 300, damping: 25 }}
210→                                onClick={(e) => e.stopPropagation()}
211→                            >
212→                                <p className="editor-close-confirm-message">
213→                                    {currentDraftIdRef.current ? 'Save changes before closing?' : 'Save as draft before closing?'}
214→                                </p>
215→                                {saveError && (
216→                                    <p className="editor-close-confirm-error">Couldn't save. Try again?</p>
217→                                )}
218→                                <div className="editor-close-confirm-actions">
219→                                    <button
220→                                        className="editor-close-confirm-discard"
221→                                        onClick={handleConfirmDiscard}
222→                                        disabled={isSavingDraft}
223→                                    >
224→                                        Discard
225→                                    </button>
226→                                    <button
227→                                        ref={saveButtonRef}
228→                                        className="editor-close-confirm-save"
229→                                        onClick={handleConfirmSaveDraft}
230→                                        disabled={isSavingDraft}
231→                                    >
232→                                        {isSavingDraft ? 'Saving...' : 'Save Draft'}
233→                                    </button>
234→                                </div>
235→                            </motion.div>
236→                        </motion.div>
237→                    )}
238→                </AnimatePresence>
239→            </motion.div>
240→        </div>
241→        </>
242→    )
243→}
244→export default Editor;
