 22→class ErrorBoundary extends React.Component {
 23→  state = { error: null };
 24→  static getDerivedStateFromError(error) {
 25→    return { error };
 26→  }
 27→  render() {
 28→    if (this.state.error) {
 29→      return <div>Error: {this.state.error.message}</div>;
 30→    }
 31→    return this.props.children;
 32→  }
 33→}
 34→
 35→/* theme for mapping css classes to lexical rols */
 36→const theme = {
 37→    paragraph: 'editor-paragraph',
 38→    heading: 'editor-heading',
 39→}
 40→
 41→const formatTimeAgo = (date) => {
 42→    if (!date) return '';
 43→    const seconds = Math.floor((Date.now() - date.getTime()) / 1000);
 44→    if (seconds < 60) return 'just now';
 45→    const minutes = Math.floor(seconds / 60);
 46→    if (minutes < 60) return `${minutes}m ago`;
 47→    const hours = Math.floor(minutes / 60);
 48→    return `${hours}h ago`;
 49→};
 50→
 51→const EditorInner = ({title, onclose, onCloseOnSave, addUploadImagesPath, setWordCount, wordCount, promptId = null, draftId = null, onDraftIdCreated, editorStateRef}) => {
 52→    const [editor] = useLexicalComposerContext();
 53→    const [editorState, setEditorState] = useState(null);
 54→    const [hasContent, setHasContent] = useState(false);
 55→    const [isSending, setIsSending] = useState(false);
 56→
 57→    // Draft state
 58→    const draftIdRef = useRef(draftId);
 59→    const [saveStatus, setSaveStatus] = useState(draftId ? 'saved' : null); // null | 'saving' | 'saved' | 'unsaved'
 60→    const [lastSavedAt, setLastSavedAt] = useState(draftId ? new Date() : null);
 61→    const [hasChanges, setHasChanges] = useState(false);
 62→    const saveTimerRef = useRef(null);
 63→    const [, forceUpdate] = useState(0);
 64→
 65→    // Expose saveTimerRef to parent so it can cancel pending auto-saves
 66→    useEffect(() => {
 67→        if (editorStateRef) {
 68→            editorStateRef.current.saveTimerRef = saveTimerRef;
 69→        }
 70→    }, [editorStateRef]);
 71→
 72→    const {session, user} = useAuth();
 73→
 74→    const queryClient = useQueryClient();
 75→    const userId = user?.userData?.[0]?.id || null;
 76→
 77→    // Keep draftIdRef in sync
 78→    useEffect(() => {
 79→        draftIdRef.current = draftId;
 80→    }, [draftId]);
 81→
 82→    // Tick the "saved X ago" display every 30s
 83→    useEffect(() => {
 84→        if (!lastSavedAt) return;
 85→        const interval = setInterval(() => forceUpdate(n => n + 1), 30000);
 86→        return () => clearInterval(interval);
 87→    }, [lastSavedAt]);
 88→
 89→    const invalidateCreatedJournalQueries = useCallback(async() => {
 90→        const invalidations = [
 91→            queryClient.invalidateQueries({queryKey: ['journals'], refetchType: 'active'}),
 92→            queryClient.invalidateQueries({queryKey: ['journals-following'], refetchType: 'active'}),
 93→            queryClient.invalidateQueries({queryKey: ['journals-for-you'], refetchType: 'active'}),
 94→            queryClient.invalidateQueries({queryKey: ['journals-search'], refetchType: 'active'}),
 95→            queryClient.invalidateQueries({queryKey: ['journals-suggestions'], refetchType: 'active'}),
 96→            queryClient.invalidateQueries({queryKey: ['journal-drafts'], refetchType: 'active'}),
 97→        ];
 98→
 99→        if(userId){
100→            invalidations.push(
101→                queryClient.invalidateQueries({queryKey: ['userJournals', userId], refetchType: 'active'}),
102→                queryClient.invalidateQueries({queryKey: ['streak', userId], refetchType: 'active'})
103→            );
104→        }
105→
106→        await Promise.allSettled(invalidations);
107→    }, [queryClient, userId]);
108→
109→    const handleSaveDraft = useCallback(async(showFeedback = true) => {
110→        if (!editorState || !session?.access_token) return;
111→        if (showFeedback) setSaveStatus('saving');
112→
113→        try {
114→            const result = await saveDraft(session.access_token, {
115→                content: editorState,
116→                title: title || '',
117→                draftId: draftIdRef.current || null,
118→                prompt_id: promptId || null,
119→            });
120→
121→            if (result?.id && !draftIdRef.current) {
122→                draftIdRef.current = result.id;
123→                if (onDraftIdCreated) onDraftIdCreated(result.id);
124→            }
125→
126→            setHasChanges(false);
127→            setSaveStatus('saved');
128→            setLastSavedAt(new Date());
129→            if (editorStateRef) {
130→                editorStateRef.current = { ...editorStateRef.current, hasChanges: false };
131→            }
132→            queryClient.invalidateQueries({queryKey: ['journal-drafts'], refetchType: 'active'});
133→        } catch (error) {
134→            console.error('Failed to save draft:', error);
135→            setSaveStatus('unsaved');
136→        }
137→    }, [editorState, session?.access_token, title, promptId, onDraftIdCreated, queryClient]);
138→
139→    // Auto-save every 30 seconds when there are changes
140→    useEffect(() => {
141→        if (!hasChanges || !editorState) return;
142→
143→        if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
144→        saveTimerRef.current = setTimeout(() => {
145→            handleSaveDraft(false);
146→        }, 30000);
147→
148→        return () => {
149→            if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
150→        };
151→    }, [editorState, hasChanges, handleSaveDraft]);
152→
153→    const handleClickPublish = async(e, title) => {
154→        e.stopPropagation();
155→        setIsSending(true);
156→
157→        try {
158→            // If we have a draft, publish it
159→            if (draftIdRef.current) {
160→                // Save latest content first
161→                await saveDraft(session.access_token, {
162→                    content: editorState,
163→                    title: title || '',
164→                    draftId: draftIdRef.current,
165→                });
166→
167→                await publishDraft(session.access_token, draftIdRef.current);
168→            } else {
169→                // Direct publish (no draft exists) — use existing save-journal flow
170→                const formdata = new FormData();
171→                if(title && editorState){
172→                    formdata.append('title', title);
173→                    formdata.append('content', editorState);
174→                }
175→                if(promptId){
176→                    formdata.append('prompt_id', promptId);
177→                }
178→                await saveJournal(session?.access_token, formdata);
179→            }
180→
181→            await invalidateCreatedJournalQueries();
182→            setHasContent(false);
183→            onCloseOnSave();
184→            addUploadImagesPath([]);
185→        } catch (error) {
186→            console.error("Error publishing journal:", error);
187→        } finally {
188→            setIsSending(false);
189→        }
190→    }
191→
192→    const onchange = useCallback((state) => {
193→        const jsonb = JSON.stringify(state.toJSON());
194→        setEditorState(jsonb)
195→        setHasChanges(true);
196→        if (saveStatus === 'saved') setSaveStatus('unsaved');
197→
198→        state.read(() => {
199→            const root = $getRoot();
200→
201→            const children = root.getChildren();
202→
203→            const hasEnoughParagraphNodes = children.length > 1
204→            const hasParargraphSize = children[0]?.__size > 0
205→
206→            const hasContent = hasParargraphSize || hasEnoughParagraphNodes
207→            setHasContent(hasContent);
208→
209→            // Calculate word count
210→            const text = root.getTextContent().trim();
211→            const words = text ? text.split(/\s+/).length : 0;
212→            setWordCount(words);
213→
214→            // Expose state to parent via ref
215→            if (editorStateRef) {
216→                editorStateRef.current = { ...editorStateRef.current, hasChanges: true, hasContent, editorState: jsonb, title };
217→            }
218→        })
219→    }, [setWordCount, saveStatus])
220→
221→    const renderSaveStatus = () => {
222→        if (!saveStatus) return null;
223→
224→        let statusText = '';
225→        let statusClass = 'editor-save-status';
226→
227→        switch (saveStatus) {
228→            case 'saving':
229→                statusText = 'Saving...';
230→                statusClass += ' editor-save-status--saving';
231→                break;
232→            case 'saved':
233→                statusText = lastSavedAt ? `Saved ${formatTimeAgo(lastSavedAt)}` : 'Saved';
234→                statusClass += ' editor-save-status--saved';
235→                break;
236→            case 'unsaved':
237→                statusText = 'Unsaved changes';
238→                statusClass += ' editor-save-status--unsaved';
239→                break;
240→            default:
241→                return null;
242→        }
243→
244→        return <span className={statusClass}>{statusText}</span>;
245→    };
246→
247→    return(
248→        <>
249→        {/* Toolbar above content */}
250→        <div className="toolbar-wrapper">
251→            <ToolBar addUploadedImagePath={addUploadImagesPath}/>
252→        </div>
253→
254→        {/* Bar loader directly under toolbar */}
255→        <div className="editor-loader-wrapper">
256→            {isSending && (
257→                <BarLoader loading={isSending} width={'100%'} height={3} color="var(--accent-purple)" speedMultiplier={0.7}/>
258→            )}
259→        </div>
260→
261→        {/* Editor content area */}
262→        <div className="editor-shell">
263→            <RichTextPlugin
264→            contentEditable={
265→            <ContentEditable
266→            className="editor-input"
267→            aria-placeholder="Write your thoughts here..."
268→            placeholder={<div className="editor-placeholder">Write your thoughts here...</div>}/>
269→            }
270→            ErrorBoundary={LexicalErrorBoundary}
271→            />
272→
273→            <ImagePlugin addUploadedImagePath={addUploadImagesPath}/>
274→            <MentionPlugin/>
275→            <HistoryPlugin/>
276→            <OnChangePlugin onChange={onchange}/>
277→
278→        </div>
279→
280→        {/* Footer: word count + save status + buttons */}
281→        <div className='editor-footer'>
282→            <div className="editor-footer-left">
283→                <span className="editor-word-count">
284→                    {wordCount} {wordCount === 1 ? 'word' : 'words'}
285→                </span>
286→                {renderSaveStatus()}
287→            </div>
288→            <div className="editor-footer-actions">
289→                <button
290→                    disabled={!hasContent || isSending}
291→                    onClick={() => handleSaveDraft(true)}
292→                    className={hasContent && !isSending ? 'editor-draft-bttn' : 'editor-draft-bttn-disabled'}
293→                >
294→                    Save Draft
295→                </button>
296→                <button
297→                    disabled={!title || !hasContent || isSending}
298→                    onClick={(e) => handleClickPublish(e, title)}
299→                    className={title && hasContent && !isSending ? 'editor-save-bttn' : 'editor-save-bttn-disabled'}
300→                >
301→                    Publish
302→                </button>
303→            </div>
304→        </div>
305→        </>
306→    )
307→}
308→
309→export default EditorInner;
