 16→  const startPosRef = useRef({ x: 0, y: 0, width: 0, height: 0 });
 17→
 18→  const [viewImage, setViewImage] = useState(false);
 19→
 20→  const{session} = useAuth();
 21→
 22→  //handle delete image from the editor
 23→  const deleteImgSync = async(imgUrl) => {
 24→    try {
 25→      const message = await deleteJournalImage(session?.access_token, imgUrl);
 26→      if(message){
 27→        // console.log(message.message)
 28→      }
 29→    } catch (error) {
 30→      console.error("Failed to delete image from storage:", error);
 31→    }
 32→  }
 33→  const handleDelete = async(e) =>{
 34→    e.stopPropagation();
 35→    let img_url = ''
 36→    const data = {
 37→      filepath: []
 38→    }
 39→    editor.update(() =>{
 40→        const node = editor.getEditorState()._nodeMap.get(nodeKey);
 41→        if(!node || !node.__src) {
 42→          throw new Error('Node not found or missing source')
 43→        }
 44→        img_url = node.__src
 45→        node.remove();
 46→    });
 47→
 48→    //only proceed if node was removed and img_url is set
 49→    if(img_url){
 50→      data.filepath.push(img_url)
 51→      await deleteImgSync(data.filepath);
 52→    }
 53→  }
 54→
 55→  const handleRotate = (e) => {
 56→    e.stopPropagation();
 57→    const newRotation = (currentRotation + 90) % 360;
 58→    setCurrentRotation(newRotation);
 59→
 60→    editor.update(() => {
 61→      const node = $getNodeByKey(nodeKey);
 62→      if (node && typeof node.setRotation === 'function') {
 63→        node.setRotation(newRotation);
 64→      }
 65→    }, {
 66→      onUpdate: () => {
 67→        editor.update(() => {});
 68→      }
 69→    });
 70→  };
 71→
 72→  // handle mouse down on resize handle
 73→  const handleMouseDown = (e, corner) => {
 74→    // e.preventDefault();
 75→    e.stopPropagation();
 76→    
 77→    const isTouchStart = e.type === 'touchstart';
 78→    const clientX = isTouchStart ? e.touches[0].clientX : e.clientX;
 79→    const clientY = isTouchStart ? e.touches[0].clientY : e.clientY;
 80→    
 81→    setIsResizing(true);
 82→    startPosRef.current = {
 83→      x: clientX,
 84→      y: clientY,
 85→      width: currentWidth || 300,
 86→      height: currentHeight || 200,
 87→    };
 88→
 89→    const handleMouseMove = (moveEvent) => {
 90→        const isTouchMove = moveEvent.type === 'touchmove'
 91→        const moveX = isTouchMove ? moveEvent.touches[0].clientX : moveEvent.clientX;
 92→        const moveY = isTouchMove ? moveEvent.touches[0].clientY : moveEvent.clientY;
 93→
 94→        const deltaX = (moveX - startPosRef.current.x) / 8;
 95→        const deltaY = (moveY - startPosRef.current.y) / 8;
 96→
 97→        let newWidth, newHeight;
 98→
 99→        if (corner === 'se') {
100→            // southeast corner - resize proportionally
101→            const aspectRatio =startPosRef.current.width / startPosRef.current.height;
102→            newWidth = Math.max(100, startPosRef.current.width + deltaX);
103→            newHeight = newWidth / aspectRatio;
104→        } else if (corner === 'e') {
105→            // east side - resize width only
106→            newWidth = Math.max(100, startPosRef.current.width + deltaX);
107→            newHeight = currentHeight;
108→        } else if (corner === 's') {
109→            // south side - resize height only
110→            newWidth = currentWidth;
111→            newHeight = Math.max(100, startPosRef.current.height + deltaY);
112→        } else if(corner === 'ne') {
113→            // northeast corner - resize proportionally
114→            const aspectRatio = startPosRef.current.width / startPosRef.current.height;
115→            newWidth = Math.max(100, startPosRef.current.width + deltaX)
116→            newHeight = newWidth / aspectRatio
117→        } else if (corner === 'sw') {
118→            // southwest corner - resize proportionally
119→            const aspectRatio = startPosRef.current.width / startPosRef.current.height;
120→            newWidth = Math.max(100, startPosRef.current.width - deltaX)
121→            newHeight = newWidth / aspectRatio
122→        } else if (corner === 'nw') {
123→            // northhwest corner - resize proportionally
124→            const aspectRatio = startPosRef.current.width / startPosRef.current.height;
125→            newWidth = Math.max(100, startPosRef.current.width - deltaX)
126→            newHeight = newWidth / aspectRatio
127→        }  else if(corner === 'n') {
128→            // south side - resize height only
129→            newWidth = currentWidth;
130→            newHeight = Math.max(100, startPosRef.current.height - deltaY);
131→        }
132→
133→        const roundedWidth = Math.round(newWidth);
134→        const roundedHeight = Math.round(newHeight);
135→
136→        setCurrentWidth(roundedWidth);
137→        setCurrentHeight(roundedHeight);
138→        startPosRef.current.width = roundedWidth;
139→        startPosRef.current.height = roundedHeight;
140→    };
141→    
142→    const handleMouseUp = () => {
143→        setIsResizing(false);
144→
145→        const finalWidth = startPosRef.current.width;
146→        const finalHeight = startPosRef.current.height;
147→
148→        // console.log(`Saving: ${finalWidth}x${finalHeight}`);//for debugging
149→      
150→        // update the Lexical node with new dimensions
151→        editor.update(() => {
152→            const node = $getNodeByKey(nodeKey);
153→            if (node && typeof node.setWidthAndHeight === 'function') {
154→                node.setWidthAndHeight(finalWidth, finalHeight);
155→            }
156→        }, {
157→                onUpdate: () => {
158→                //forcing a statechange so if user resize the image it will update the editorstate
159→                editor.update(() =>{
160→                //empty because i only used this for triggering the OnChangePlugin
161→                    })
162→                }
163→            }
164→        );
165→
166→        //remove all listeners after mouse up
167→        document.removeEventListener('touchmove', handleMouseMove)
168→        document.removeEventListener('mousemove', handleMouseMove);
169→        document.removeEventListener('mouseup', handleMouseUp);
170→        document.removeEventListener('touchend', handleMouseUp)
171→    };
172→
173→    //add all event listerner after mouse down or mouse hold click 
174→    document.addEventListener('touchmove', handleMouseMove, {passive: false})
175→    document.addEventListener('mousemove', handleMouseMove);
176→    document.addEventListener('mouseup', handleMouseUp);
177→    document.addEventListener('touchend', handleMouseUp)
178→};
179→
180→
181→  // handle image click for selection
182→  const handleImageClick = () => {
183→    setIsSelected(!isSelected);
184→  };
185→
186→  //handle image  click for view
187→  const handleViewImage = () => {
188→    // console.log('view img')
189→    if(!isEditable){
190→      setViewImage(true)
191→    } else {
192→      return
193→    }
194→    
195→  }
196→
197→  // click outside to deselect
198→  useEffect(() => {
199→    const handleClickOutside = (e) => {
200→      if (imageRef.current && !imageRef.current.contains(e.target)) {
201→        setIsSelected(false);
202→      }
203→    };
204→
205→    document.addEventListener('mousedown', handleClickOutside);
206→    return () => document.removeEventListener('mousedown', handleClickOutside);
207→  }, []);
208→
209→  return (
210→    <>
211→    {viewImage && (
212→      <img
213→        onClick={() => setViewImage(!viewImage)}
214→        className='image-view'
215→        src={src}
216→        alt="view-image"
217→        style={{
218→          transform: `rotate(${currentRotation}deg) scale(1.2)`,
219→          transition: 'transform 0.3s ease',
220→        }}
221→      />
222→    )}
223→
224→    <div
225→    className='image-wrapper'
226→      ref={imageRef}
227→      style={{
228→        cursor: isResizing ? 'nwse-resize' : 'pointer',
229→      }}
230→      onClick={isEditable ? handleImageClick : handleViewImage}
231→    >
232→   
233→      <AnimatePresence>
234→      <motion.img
235→        initial={{opacity: 0}}
236→        animate={{opacity: 1, transition: {type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
237→        exit={{ opacity: 0, y: -20,
238→          transition: { 
239→            duration: 0.2,
240→            ease: "easeOut"
241→          }
242→        }}
243→
244→        src={src}
245→        alt="content"
246→        style={{
247→          borderRadius: '5px',
248→          width: `${currentWidth}px`,
249→          height: `${currentHeight}px`,
250→          display: 'block',
251→          border: isSelected ? '1px solid rgba(153, 200, 255, 0.99)' : '2px solid transparent',
252→          userSelect: 'none',
253→          transform: `rotate(${currentRotation}deg)`,
254→          transition: isResizing ? 'none' : 'transform 0.3s ease',
255→        }}
256→        draggable={false}
257→        onClick={() => handleViewImage()}
258→        className='image-content'
259→      />
260→      </AnimatePresence>
261→
262→      {loading && (
263→        <div className="image-loading-overlay">
264→          <div className="image-loading-spinner" />
265→        </div>
266→      )}
267→
268→      {isEditable && (
269→      <div className='image-actions'>
270→        <div onClick={(e) => handleRotate(e)} className='image-action-btn' title='Rotate image'>
271→          <svg xmlns="http://www.w3.org/2000/svg" height="20px" viewBox="0 -960 960 960" width="20px" fill="#FFFFFF"><path d="M482-160q-134 0-228-93t-94-227q0-134 94-228t228-94q62 0 118 23t98 65V-840h80v240H538v-80h128q-30-38-74.5-59T482-740q-100 0-170 70.5T242-480q0 100 70 170t170 70q77 0 139-44t87-116h84q-28 106-114 173t-196 67Z"/></svg>
272→        </div>
273→        <div onClick={(e) => handleDelete(e)} className='image-action-btn' title='Delete image'>
274→          <svg xmlns="http://www.w3.org/2000/svg" height="20px" viewBox="0 -960 960 960" width="20px" fill="#FFFFFF"><path d="m256-200-56-56 224-224-224-224 56-56 224 224 224-224 56 56-224 224 224 224-56 56-224-224-224 224Z"/></svg>
275→        </div>
276→      </div>
277→      )}
278→
279→      {isSelected && isEditable &&(
280→        <>
281→          {/* southeast corner handle - proportional resize */}
282→          <div
283→            onMouseDown={(e) => handleMouseDown(e, 'se')}
284→            onTouchStart={(e) => handleMouseDown(e, 'se')}
285→            className='southeast-side-handle'
286→          />
287→
288→          {/* southwest corner handle - proportional resize */}
289→          <div
290→            onMouseDown={(e) => handleMouseDown(e, 'sw')}
291→            onTouchStart={(e) => handleMouseDown(e, 'sw')} 
292→            className='southwest-side-handle'
293→          />
294→
295→          {/* northeast corner handle - proportional resize */}
296→          <div
297→            onMouseDown={(e) => handleMouseDown(e, 'ne')}
298→            onTouchStart={(e) => handleMouseDown(e, 'ne')} 
299→            className='northeast-side-handle'
300→          />
301→
302→          {/* northwest corner handle - proportional resize */}
303→          <div
304→            onMouseDown={(e) => handleMouseDown(e, 'nw')}
305→            onTouchStart={(e) => handleMouseDown(e, 'nw')} 
306→            className='northwest-side-handle'
307→          />
308→
309→          {/* east side handle - width only */}
310→          <div
311→            onMouseDown={(e) => handleMouseDown(e, 'e')}
312→            onTouchStart={(e) => handleMouseDown(e, 'e')} 
313→            className='east-side-handle'
314→          />
315→
316→          {/* south side handle - height only */}
317→          <div
318→            onMouseDown={(e) => handleMouseDown(e, 's')}
319→            onTouchStart={(e) => handleMouseDown(e, 's')} 
320→            className='south-side-handle'
321→          />
322→
323→           {/* north side handle - height only */}
324→          <div
325→            onMouseDown={(e) => handleMouseDown(e, 'n')}
326→            onTouchStart={(e) => handleMouseDown(e, 'n')} 
327→            className='north-side-handle'
328→          />
329→
330→          {/* dimensions display */}
331→          <div
332→          className='dimension-display'
333→          >
334→            {currentWidth} × {currentHeight}
335→          </div>
336→        </>
337→      )}
338→    </div>
339→    </>
340→  );
341→}
342→export default ResizableImageComponent;
